if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
// Call GDA.api.health-scan webhook directly, no n8n credential binding needed.
// Mirrors the working pattern used by GDA.cron.master-scanner.
const url = 'https://n8n.csr-llc.tech/webhook/gda-health-scan';
const startedAt = new Date().toISOString();

let result;
try {
  result = await this.helpers.httpRequest({
    method: 'POST',
    url: url,
    headers: {
      'Content-Type': 'application/json',
      'x-gda-key': $env.GDA_WEBHOOK_HEADER_VALUE_V2
    },
    body: { auth_key: $env.GDA_API_KEY_2026 },
    json: true,
    returnFullResponse: true,
    timeout: 180000,
    ignoreHttpStatusErrors: true
  });
} catch(e) {
  return [{ json: {
    status: 'error',
    error: e.message,
    startedAt,
    finishedAt: new Date().toISOString()
  }}];
}

const body = result.body || {};
return [{ json: {
  status: body.status || 'unknown',
  pass_rate: body.pass_rate || null,
  passed: body.passed ?? null,
  failed: body.failed ?? null,
  timed_out: body.timed_out ?? null,
  total: body.total ?? null,
  duration_ms: body.duration_ms || null,
  httpStatus: result.statusCode,
  startedAt,
  finishedAt: new Date().toISOString()
}}];

